    code: "#include <algorithm>\n#include <cstdlib>\nusing namespace std;\n\n// TreeNode definition (provided by LeetCode judge)\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode* l, TreeNode* r) : val(x), left(l), right(r) {}\n};\n\nclass Solution {\n    // Returns the height of the subtree rooted at node,\n    // or -1 if any subtree is found to be unbalanced.\n    int height(TreeNode* node) {\n        if (!node) return 0;\n\n        int lh = height(node->left);\n        if (lh == -1) return -1;          // early-exit: left side already broken\n\n        int rh = height(node->right);\n        if (rh == -1) return -1;          // early-exit: right side already broken\n\n        if (abs(lh - rh) > 1) return -1; // this node violates the balance condition\n\n        return max(lh, rh) + 1;\n    }\n\npublic:\n    bool isBalanced(TreeNode* root) {\n        return height(root) != -1;\n    }\n};\n",
