    code: "#include <vector>\n#include <string>\nusing namespace std;\n\nclass Solution {\npublic:\n    int numDistinct(string s, string t) {\n        int m = s.size(), n = t.size();\n\n        // dp[j] = number of ways to form t[0..j-1] using s characters seen so far.\n        // Use long long internally to avoid overflow before clamping to int.\n        vector<long long> dp(n + 1, 0);\n        dp[0] = 1; // empty target is always matched exactly one way\n\n        // Iterate over each character of s\n        for (int i = 0; i < m; ++i) {\n            // Traverse t right-to-left so we read dp[j-1] from the previous row\n            for (int j = n; j >= 1; --j) {\n                if (s[i] == t[j - 1]) {\n                    dp[j] += dp[j - 1];\n                }\n            }\n        }\n\n        return static_cast<int>(dp[n]);\n    }\n};\n",
