    code: "#include <vector>\n#include <string>\n#include <functional>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<vector<string>> partition(string s) {\n        int n = s.size();\n\n        // isPalin[i][j] = true iff s[i..j] is a palindrome\n        vector<vector<bool>> isPalin(n, vector<bool>(n, false));\n\n        // Every single character is a palindrome\n        for (int i = 0; i < n; ++i) isPalin[i][i] = true;\n\n        // Fill spans of length 2 and above\n        for (int len = 2; len <= n; ++len) {\n            for (int i = 0; i <= n - len; ++i) {\n                int j = i + len - 1;\n                if (s[i] == s[j]) {\n                    // Inner span (i+1..j-1) is either empty (len==2) or already palindrome\n                    isPalin[i][j] = (len == 2) || isPalin[i + 1][j - 1];\n                }\n            }\n        }\n\n        vector<vector<string>> result;\n        vector<string> current;\n\n        // Backtracking: try every palindromic prefix starting at 'start'\n        function<void(int)> backtrack = [&](int start) {\n            if (start == n) {\n                result.push_back(current);\n                return;\n            }\n            for (int end = start; end < n; ++end) {\n                if (isPalin[start][end]) {\n                    current.push_back(s.substr(start, end - start + 1));\n                    backtrack(end + 1);\n                    current.pop_back();\n                }\n            }\n        };\n\n        backtrack(0);\n        return result;\n    }\n};\n",
