    code: "\n#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<bool> checkIfPrerequisite(int numCourses,\n                                     vector<vector<int>>& prerequisites,\n                                     vector<vector<int>>& queries) {\n        // reach[i][j] == true  =>  course i is a prerequisite of course j\n        vector<vector<bool>> reach(numCourses, vector<bool>(numCourses, false));\n\n        // Seed direct edges\n        for (const auto& p : prerequisites)\n            reach[p[0]][p[1]] = true;\n\n        // Floyd-Warshall transitive closure\n        // For each intermediate k, i can reach j if i reaches k and k reaches j\n        for (int k = 0; k < numCourses; ++k)\n            for (int i = 0; i < numCourses; ++i)\n                if (reach[i][k])                         // prune inner loop early\n                    for (int j = 0; j < numCourses; ++j)\n                        reach[i][j] = reach[i][j] || reach[k][j];\n\n        // Answer every query in O(1)\n        vector<bool> ans;\n        ans.reserve(queries.size());\n        for (const auto& q : queries)\n            ans.push_back(reach[q[0]][q[1]]);\n\n        return ans;\n    }\n};\n",
