    code: "#include <vector>\n#include <unordered_map>\nusing namespace std;\n\nclass FindSumPairs {\npublic:\n    FindSumPairs(vector<int>& nums1, vector<int>& nums2)\n        : nums2_(nums2)\n    {\n        // nums1 never changes — build its freq map once\n        for (int x : nums1) ++freq1_[x];\n        // nums2 can be updated — keep freq map in sync\n        for (int x : nums2) ++freq2_[x];\n    }\n\n    // Increment nums2[index] by val; keep freq2_ consistent\n    void add(int index, int val) {\n        --freq2_[nums2_[index]];   // remove old value\n        nums2_[index] += val;\n        ++freq2_[nums2_[index]];   // record new value\n    }\n\n    // Count pairs (i,j) where nums1[i] + nums2[j] == tot\n    int count(int tot) {\n        int res = 0;\n        for (auto& [x, fx] : freq1_) {\n            int need = tot - x;\n            auto it = freq2_.find(need);\n            if (it != freq2_.end())\n                res += fx * it->second;\n        }\n        return res;\n    }\n\nprivate:\n    vector<int> nums2_;                 // mutable copy of nums2\n    unordered_map<int,int> freq1_;      // frequency of nums1 values (static)\n    unordered_map<int,int> freq2_;      // frequency of nums2 values (dynamic)\n};\n\n/**\n * Your FindSumPairs object will be instantiated and called as such:\n * FindSumPairs* obj = new FindSumPairs(nums1, nums2);\n * obj->add(index, val);\n * int param_2 = obj->count(tot);\n */",
