    code: "#include <cstdint>\nusing namespace std;\n\nclass Solution {\npublic:\n    int hammingWeight(int n) {\n        int count = 0;\n        uint32_t bits = static_cast<uint32_t>(n); // avoid signed overflow UB\n        // Each iteration clears the lowest set bit; loop runs once per set bit.\n        while (bits) {\n            bits &= bits - 1;  // drop the rightmost 1-bit\n            ++count;\n        }\n        return count;\n    }\n};\n",
