    code: "#include <cstddef>\nusing namespace std;\n\n// Definition for singly-linked list.\nstruct ListNode {\n    int val;\n    ListNode *next;\n    ListNode() : val(0), next(nullptr) {}\n    ListNode(int x) : val(x), next(nullptr) {}\n    ListNode(int x, ListNode *next) : val(x), next(next) {}\n};\n\nclass Solution {\npublic:\n    ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {\n        ListNode dummy;               // sentinel; avoids edge-case on first node\n        ListNode* tail = &dummy;\n        int carry = 0;\n\n        // Continue while there are unprocessed digits or a pending carry\n        while (l1 || l2 || carry) {\n            int digit = carry;\n            if (l1) { digit += l1->val; l1 = l1->next; }\n            if (l2) { digit += l2->val; l2 = l2->next; }\n\n            carry = digit / 10;\n            tail->next = new ListNode(digit % 10);\n            tail = tail->next;\n        }\n\n        return dummy.next;\n    }\n};\n",
