    code: "#include <vector>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool canAttendMeetings(vector<vector<int>>& intervals) {\n        // Sort by start time so overlaps can only occur between adjacent meetings\n        sort(intervals.begin(), intervals.end(),\n             [](const vector<int>& a, const vector<int>& b) {\n                 return a[0] < b[0];\n             });\n\n        for (int i = 1; i < (int)intervals.size(); ++i) {\n            // Overlap exists if the next meeting starts before the current one ends\n            if (intervals[i][0] < intervals[i - 1][1]) {\n                return false;\n            }\n        }\n        return true;\n    }\n};",
    timeComplexity: "O(n log n)",
