    code: "#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    int searchInsert(vector<int>& nums, int target) {\n        int lo = 0, hi = static_cast<int>(nums.size()) - 1;\n\n        while (lo <= hi) {\n            int mid = lo + (hi - lo) / 2; // avoids potential overflow vs (lo+hi)/2\n\n            if (nums[mid] == target)\n                return mid;\n            else if (nums[mid] < target)\n                lo = mid + 1;\n            else\n                hi = mid - 1;\n        }\n\n        // lo is the insertion point: all elements to its left are < target,\n        // all elements from lo onward are > target.\n        return lo;\n    }\n};",
