    routeSlug: "79-word-search",
    summary: "Given a 2D character grid and a target word, determine whether the word can be formed by traversing adjacent (up/down/left/right) cells in sequence, where each cell may be used at most once per path.",
    approach: "- For every cell in the grid, attempt to start a DFS that matches the word character by character.\n- At each step, if the current cell matches the needed character, temporarily mark it visited (in-place) to prevent reuse, then recurse into all four neighbors.\n- If the full word is matched (index reaches `word.size()`), propagate `true` back immediately.\n- On backtrack, restore the cell's original character so other search paths can use it.",
    code: "#include <vector>\n#include <string>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool exist(vector<vector<char>>& board, string word) {\n        int m = board.size(), n = board[0].size();\n        for (int r = 0; r < m; ++r)\n            for (int c = 0; c < n; ++c)\n                if (dfs(board, word, 0, r, c))\n                    return true;\n        return false;\n    }\n\nprivate:\n    // Returns true if word[idx..] can be matched starting from (r, c).\n    bool dfs(vector<vector<char>>& board, const string& word, int idx, int r, int c) {\n        if (idx == (int)word.size()) return true;  // entire word matched\n\n        int m = board.size(), n = board[0].size();\n        if (r < 0 || r >= m || c < 0 || c >= n) return false;  // out of bounds\n        if (board[r][c] != word[idx]) return false;             // char mismatch\n\n        // Mark visited in-place to avoid reusing this cell in the current path.\n        char saved = board[r][c];\n        board[r][c] = '#';\n\n        constexpr int dr[] = {-1, 1, 0,  0};\n        constexpr int dc[] = { 0, 0, 1, -1};\n        for (int d = 0; d < 4; ++d)\n            if (dfs(board, word, idx + 1, r + dr[d], c + dc[d]))\n                return true;\n\n        board[r][c] = saved;  // restore on backtrack\n        return false;\n    }\n};\n",
    timeComplexity: "O(M * N * 4^L) where M and N are the grid dimensions and L is the word length — each cell can spawn up to 4 recursive branches L levels deep.",
    spaceComplexity: "O(L) for the recursion call stack, where L is the length of the word.",
